                        <td className="px-6 py-4 whitespace-nowrap"><StatusBadge status={apt.status} /></td>
                        <td className="px-6 py-4 whitespace-nowrap text-right">
                            <Button size="sm" variant="ghost" icon={Eye} onClick={() => onView(apt)}>{t('view')}</Button>
                        </td>
                    </tr>
                  ))
                )}
              </tbody>
            </table>
          </div>

          <div className="flex flex-col sm:flex-row justify-between items-center p-4 border-t border-slate-200 dark:border-slate-700 gap-4 mt-auto">
                <div className="flex flex-col sm:flex-row items-center gap-4 text-sm text-slate-500">
                    <span>{t('patients_pagination_showing')} {paginated.length} {t('patients_pagination_of')} {filtered.length}</span>
                    <div className="flex items-center gap-2">
                        <span className="text-xs whitespace-nowrap">{t('patients_pagination_rows')}</span>
                        <select 
                          className="bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-lg px-2 py-1 text-xs outline-none cursor-pointer"
                          value={itemsPerPage}
                          onChange={(e) => { setItemsPerPage(parseInt(e.target.value)); setCurrentPage(1); }}
                        >
                          <option value={10}>10</option>
                          <option value={15}>15</option>
                          <option value={20}>20</option>
                          <option value={50}>50</option>
                        </select>
                    </div>
                </div>
                <div className="flex gap-2">
                    <Button size="sm" variant="secondary" onClick={() => setCurrentPage(p => Math.max(1, p-1))} disabled={currentPage === 1} icon={ChevronLeft}>{t('billing_pagination_prev')}</Button>
                    <Button size="sm" variant="secondary" onClick={() => setCurrentPage(p => Math.min(totalPages, p+1))} disabled={currentPage === totalPages} icon={ChevronRight}>{t('billing_pagination_next')}</Button>
                </div>
            </div>
        </div>
    );
};

export const Appointments = () => {
  const location = useLocation();
  const [appointments, setAppointments] = useState<Appointment[]>([]);
  const [staff, setStaff] = useState<MedicalStaff[]>([]);
  const [patients, setPatients] = useState<Patient[]>([]);
  const [loading, setLoading] = useState(true);
  const [viewMode, setViewMode] = useState<'grid' | 'list' | 'history'>('grid');
  const [selectedDate, setSelectedDate] = useState(new Date());

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isViewDetailModalOpen, setIsViewDetailModalOpen] = useState(false);
  const [editingAppointment, setEditingAppointment] = useState<Appointment | null>(null);
  const [viewingAppointment, setViewingAppointment] = useState<Appointment | null>(null);
  const [formData, setFormData] = useState({ patientId: '', staffId: '', date: formatDate(new Date()), time: '09:00', type: 'Consultation', reason: '' });

  const [patientSearch, setPatientSearch] = useState('');
  const [showPatientResults, setShowPatientResults] = useState(false);
  const patientSearchRef = useRef<HTMLDivElement>(null);

  const [confirmState, setConfirmState] = useState({ isOpen: false, title: '', message: '', action: () => {} });
  const [processStatus, setProcessStatus] = useState<'idle' | 'processing' | 'success' | 'error'>('idle');
  const [processMessage, setProcessMessage] = useState('');

  const { t } = useTranslation();
  const { user: currentUser } = useAuth();
  const canManage = hasPermission(currentUser, Permissions.MANAGE_APPOINTMENTS);

  useHeader(
    t('appointments_title'),
    t('appointments_subtitle'),
    canManage ? <Button onClick={() => { openNewModal(); }} icon={Plus}>{t('dashboard_today')}</Button> : null
  );

  const loadData = async (isSilent = false) => {
    if (!isSilent) setLoading(true);
    try {
      const [apts, stf, pts] = await Promise.all([api.getAppointments(), api.getStaff(), api.getPatients()]);
      setAppointments(Array.isArray(apts) ? apts : []);
      setStaff(Array.isArray(stf) ? stf : []);
      setPatients(Array.isArray(pts) ? pts : []);
    } catch (e) { console.error(e); } finally { if (!isSilent) setLoading(false); }
  };

  useEffect(() => { 
    loadData(); 
  }, []);

  useEffect(() => {
    const state = location.state as any;
    if (state?.trigger === 'new' && canManage) {
      openNewModal();
    }
  }, [location.state, canManage]);

  const openNewModal = () => {
    setEditingAppointment(null); 
    setFormData({ patientId: '', staffId: '', date: formatDate(selectedDate), time: '09:00', type: 'Consultation', reason: '' }); 
    setPatientSearch(''); 
    setIsModalOpen(true);
  };

  const openViewDetailModal = (apt: Appointment) => {
    setViewingAppointment(apt);
    setIsViewDetailModalOpen(true);
  };

  useEffect(() => {
    const handleClickOutside = (e: MouseEvent) => {
      if (patientSearchRef.current && !patientSearchRef.current.contains(e.target as Node)) {
        setShowPatientResults(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const dailyAppointments = useMemo(() => {
    return appointments
      .filter(apt => isSameDay(new Date(apt.datetime), selectedDate))
      .sort((a, b) => {
        const aIsPaid = a.billingStatus === 'paid' || (a.totalAmount !== undefined && a.paidAmount !== undefined && a.paidAmount >= a.totalAmount);
        const bIsPaid = b.billingStatus === 'paid' || (b.totalAmount !== undefined && b.paidAmount !== undefined && b.paidAmount >= b.totalAmount);
        if (aIsPaid && !bIsPaid) return -1;
        if (!aIsPaid && bIsPaid) return 1;
        return new Date(a.datetime).getTime() - new Date(b.datetime).getTime();
      });
  }, [appointments, selectedDate]);

  const appointmentsByDoctor = useMemo(() => {
    const doctorsWithAppointments = staff.filter(s => (s.type === 'doctor' || s.type === 'nurse') && dailyAppointments.some(a => a.staffId === s.id));
    return doctorsWithAppointments.map(doc => ({ doctor: doc, appointments: dailyAppointments.filter(a => a.staffId === doc.id) }));
  }, [dailyAppointments, staff]);

  const handleStatusUpdate = async (id: number, status: string, patientName: string) => {
    setProcessStatus('processing');
    setProcessMessage(`Updating status for ${patientName}...`);
    try {
      if (status === 'in_progress') {
        const apt = appointments.find(a => a.id === id);
        if (apt) {
          const otherInProgress = appointments.find(a => a.staffId === apt.staffId && a.status === 'in_progress');
          if (otherInProgress) await api.updateAppointmentStatus(otherInProgress.id, 'checked_in');
        }
      }
      await api.updateAppointmentStatus(id, status);
      await loadData(true);
      setProcessStatus('idle');
    } catch (e: any) { 
      setProcessStatus('error'); 
      setProcessMessage(e.response?.data?.error || e.message || 'Failed'); 
      setTimeout(() => setProcessStatus('idle'), 2000); 
    }
  };

  const handleCancel = (id: number) => {
    setConfirmState({
      isOpen: true, title: t('appointments_cancel_dialog_title'), message: t('appointments_cancel_dialog_message'),
      action: async () => {
        setProcessStatus('processing');
        setProcessMessage(t('appointments_process_cancelling'));
        try { 
          await api.cancelAppointment(id); 
          await loadData(true); 
          setProcessStatus('success'); 
          setTimeout(() => setProcessStatus('idle'), 1500); 
        } 
        catch (e: any) { 
          setProcessStatus('error'); 
          setProcessMessage(e.response?.data?.error || e.message || t('appointments_process_cancel_fail')); 
          setTimeout(() => setProcessStatus('idle'), 2000); 
        }
      }
    });
  };

  const handleFormSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.patientId || !formData.staffId) return;

    setProcessStatus('processing');
    setProcessMessage(editingAppointment ? t('appointments_process_updating') : t('appointments_process_creating'));
    try {
      const payload = { ...formData, patientId: parseInt(formData.patientId), staffId: parseInt(formData.staffId), datetime: `${formData.date}T${formData.time}` };
      if (editingAppointment) await api.updateAppointment(editingAppointment.id, payload);
      else await api.createAppointment(payload);
      await loadData(true);
      setProcessStatus('success');
      setTimeout(() => { setIsModalOpen(false); setProcessStatus('idle'); }, 1500);
    } catch (e: any) { 
      setProcessStatus('error'); 
      setProcessMessage(e.response?.data?.error || e.message || t('appointments_process_save_fail')); 
      setTimeout(() => setProcessStatus('idle'), 2000); 
    }
  };

  const selectedDoctorForFee = useMemo(() => {
    return staff.find(s => s.id.toString() === formData.staffId);
  }, [formData.staffId, staff]);

  const filteredPatientsForModal = useMemo(() => {
    if (!patientSearch) return patients.slice(0, 5);
    return patients.filter(p => 
      p.fullName.toLowerCase().includes(patientSearch.toLowerCase()) || 
      p.patientId.toLowerCase().includes(patientSearch.toLowerCase())
    ).slice(0, 5);
  }, [patients, patientSearch]);

  const selectedPatientData = useMemo(() => {
    return patients.find(p => p.id.toString() === formData.patientId);
  }, [formData.patientId, patients]);

  const openEditModal = (apt: Appointment) => {
    setEditingAppointment(apt);
    setFormData({
        patientId: apt.patientId.toString(),
        staffId: apt.staffId.toString(),
        date: apt.datetime.split('T')[0],
        time: apt.datetime.split('T')[1].slice(0, 5),
        type: apt.type,
        reason: apt.reason || ''
    });
    setPatientSearch(apt.patientName);
    setIsModalOpen(true);
  };

  return (
    <div className="space-y-6">
      {processStatus !== 'idle' && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center bg-black/60 backdrop-blur-sm animate-in fade-in duration-200">
          <div className="bg-white dark:bg-slate-900 p-8 rounded-3xl shadow-2xl flex flex-col items-center max-w-sm w-full mx-4 text-center">
            {processStatus === 'processing' && <Loader2 className="w-12 h-12 text-primary-600 animate-spin mb-4" />}
            {processStatus === 'success' && <CheckCircle className="w-12 h-12 text-green-600 mb-4" />}
            {processStatus === 'error' && <XCircle className="w-12 h-12 text-red-600 mb-4" />}
            <h3 className="text-xl font-bold text-slate-800 dark:text-white mb-2">{processStatus === 'processing' ? t('processing') : processStatus === 'success' ? t('success') : t('error')}</h3>
            <p className="text-slate-500 dark:text-slate-400 mb-6">{processMessage}</p>
            {processStatus === 'error' && <Button variant="secondary" onClick={() => setProcessStatus('idle')} className="w-full">{t('close')}</Button>}
          </div>
        </div>
      )}

      <Card className="!p-2 flex flex-col lg:flex-row justify-between items-center gap-4">
        {/* Left Side: Date Controls */}
        <div className="flex items-center gap-2 w-full lg:w-auto">
          {viewMode !== 'history' ? (
            <>
                <div className="flex items-center gap-1">
                    <Button size="sm" variant="outline" icon={ChevronLeft} onClick={() => setSelectedDate(new Date(selectedDate.setDate(selectedDate.getDate() - 1)))} />
                    <div className="relative group">
                    <div className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none group-focus-within:text-primary-500"><CalendarDays size={14}/></div>
                    <Input type="date" value={formatDate(selectedDate)} onChange={e => setSelectedDate(new Date(e.target.value))} className="w-auto pl-8 pr-3 font-bold border-slate-200 text-xs py-1.5 h-8" />
                    </div>
                    <Button size="sm" variant="outline" icon={ChevronRight} onClick={() => setSelectedDate(new Date(selectedDate.setDate(selectedDate.getDate() + 1)))} />
                </div>
                <Button size="sm" variant="secondary" className="h-8 text-xs" onClick={() => setSelectedDate(new Date())}>{t('dashboard_today')}</Button>
            </>
          ) : (
             <div className="flex items-center gap-2 px-2 py-1 bg-slate-50 dark:bg-slate-900 rounded-lg border border-slate-200 dark:border-slate-700">
               <History size={16} className="text-slate-400" />
               <span className="text-xs font-bold text-slate-600 dark:text-slate-300">All History</span>
             </div>
          )}
        </div>

        {/* Right Side: View Tabs */}
        <div className="flex bg-slate-100 dark:bg-slate-900 p-1 rounded-xl shadow-inner border border-slate-200 dark:border-slate-800 shrink-0 w-full lg:w-auto justify-center">
            <button 
                onClick={() => setViewMode('grid')}
                className={`flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-[10px] font-black uppercase tracking-widest transition-all flex-1 lg:flex-none justify-center ${viewMode === 'grid' ? 'bg-white dark:bg-slate-800 text-primary-600 shadow-sm' : 'text-slate-500 hover:text-slate-800 dark:hover:text-slate-200'}`}
            >
                <LayoutGrid size={14} />
                <span className="hidden sm:inline">{t('appointments_view_queue')}</span>
            </button>
            <button 
                onClick={() => setViewMode('list')}
                className={`flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-[10px] font-black uppercase tracking-widest transition-all flex-1 lg:flex-none justify-center ${viewMode === 'list' ? 'bg-white dark:bg-slate-800 text-primary-600 shadow-sm' : 'text-slate-500 hover:text-slate-800 dark:hover:text-slate-200'}`}
            >
                <ListIcon size={14} />
                <span className="hidden sm:inline">{t('appointments_view_list')}</span>
            </button>
            <button 
                onClick={() => setViewMode('history')}
                className={`flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-[10px] font-black uppercase tracking-widest transition-all flex-1 lg:flex-none justify-center ${viewMode === 'history' ? 'bg-white dark:bg-slate-800 text-primary-600 shadow-sm' : 'text-slate-500 hover:text-slate-800 dark:hover:text-slate-200'}`}
            >
                <History size={14} />
                <span className="hidden sm:inline">{t('operations_tab_history')}</span>
            </button>
        </div>
      </Card>

      {loading ? (
        <div className="text-center py-20 text-slate-400">{t('loading')}</div>
      ) : viewMode === 'grid' ? (
        <div className="flex gap-6 overflow-x-auto pb-4 custom-scrollbar -mx-6 px-6">
          {appointmentsByDoctor.length === 0 ? (<div className="flex-1 text-center py-20 border-2 border-dashed border-slate-200 dark:border-slate-700 rounded-xl w-full"><p className="text-slate-500">{t('appointments_list_empty')}</p></div>) : 
           appointmentsByDoctor.map(({ doctor, appointments }) => (<DoctorQueueColumn key={doctor.id} doctor={doctor} appointments={appointments} onStatusUpdate={handleStatusUpdate} onCancel={handleCancel} canManage={canManage} />))}
        </div>
      ) : viewMode === 'list' ? (
        <Card className="!p-0"><ListView appointments={dailyAppointments} onEdit={openEditModal} onView={openViewDetailModal} onCancel={handleCancel} canManage={canManage} /></Card>
      ) : (
        <Card className="!p-0"><HistoryView appointments={appointments} onView={openViewDetailModal} /></Card>
      )}

      {/* NEW/EDIT MODAL */}
      <Modal isOpen={isModalOpen} onClose={() => setIsModalOpen(false)} title={editingAppointment ? t('appointments_modal_edit_title') : t('appointments_modal_title')}>
        <form onSubmit={handleFormSubmit} className="space-y-5">

          <div className="space-y-1.5" ref={patientSearchRef}>
            <label className="block text-sm font-bold text-slate-700 dark:text-slate-300">
              {t('appointments_form_select_patient')}
            </label>
            {selectedPatientData && !showPatientResults ? (
              <div className="flex items-center justify-between p-3.5 bg-primary-50 dark:bg-primary-900/20 border border-primary-200 dark:border-primary-800 rounded-2xl transition-all">
                 <div className="flex items-center gap-3">
                   <div className="w-10 h-10 rounded-full bg-primary-100 dark:bg-primary-800 flex items-center justify-center text-primary-600 font-bold text-sm">
                      {selectedPatientData.fullName.charAt(0)}
                   </div>
                   <div className="flex flex-col">
                     <span className="font-black text-primary-900 dark:text-primary-100 leading-none mb-1">{selectedPatientData.fullName}</span>
                     <span className="text-[10px] text-primary-600 dark:text-primary-400 font-black tracking-widest uppercase">ID: {selectedPatientData.patientId}</span>
                   </div>
                 </div>
                 {!editingAppointment && (
                    <button type="button" onClick={() => { setFormData({...formData, patientId: ''}); setPatientSearch(''); setShowPatientResults(true); }} className="p-1.5 hover:bg-primary-100 dark:hover:bg-primary-800 rounded-full transition-colors">
                      <X size={16} className="text-primary-600" />
                    </button>
                 )}
              </div>
            ) : (
              <div className="relative">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-4 h-4" />
                <input 
                  type="text"
                  placeholder={t('patients_search_placeholder')}
                  className="pl-9 pr-4 py-3 w-full rounded-2xl border border-slate-300 dark:border-slate-700 bg-white dark:bg-slate-900 text-sm focus:ring-2 focus:ring-primary-500/20 focus:border-primary-500 outline-none transition-all"
                  value={patientSearch}
                  onChange={(e) => { setPatientSearch(e.target.value); setShowPatientResults(true); }}
                  onFocus={() => setShowPatientResults(true)}
                  disabled={!!editingAppointment}
                />
                {showPatientResults && (
                  <div className="absolute z-50 w-full mt-2 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-2xl shadow-2xl overflow-hidden animate-in fade-in zoom-in-95 duration-200 max-h-56 overflow-y-auto custom-scrollbar">
                    {filteredPatientsForModal.length > 0 ? (
                      filteredPatientsForModal.map(p => (
                        <button key={p.id} type="button" className="w-full px-4 py-3 text-left hover:bg-slate-50 dark:hover:bg-slate-700 border-b last:border-0 border-slate-100 dark:border-slate-700 flex justify-between items-center transition-colors" onClick={() => { setFormData({ ...formData, patientId: p.id.toString() }); setPatientSearch(p.fullName); setShowPatientResults(false); }}>
                          <div className="flex flex-col">
                            <span className="font-bold text-slate-900 dark:text-white text-sm">{p.fullName}</span>
                            <span className="text-[10px] text-slate-500 font-mono">ID: {p.patientId}</span>
                          </div>
                          <ChevronRight size={14} className="text-slate-300" />
                        </button>
                      ))
                    ) : (
                        <div className="p-4 text-center text-slate-400 text-xs italic">{t('no_data')}</div>
                    )}
                  </div>
                )}
              </div>
            )}
          </div>

          <Select label={t('appointments_form_select_staff')} required value={formData.staffId} onChange={e => setFormData({...formData, staffId: e.target.value})}>
            <option value="">{t('appointments_form_select_staff')}</option>
            {staff.filter(s => s.type === 'doctor' && s.status === 'active').map(s => {
              const availability = s.availableTimeStart ? ` [${s.availableTimeStart.slice(0,5)} - ${s.availableTimeEnd?.slice(0,5)}]` : '';
              return (
                <option key={s.id} value={s.id}>{s.fullName} ({s.specialization}){availability}</option>
              );
            })}
          </Select>

          <div className="grid grid-cols-2 gap-4">
            <Input label={t('date')} type="date" required value={formData.date} onChange={e => setFormData({...formData, date: e.target.value})} />
            <Input label={t('appointments_form_time')} type="time" required value={formData.time} onChange={e => setFormData({...formData, time: e.target.value})} />
          </div>

          <Select label={t('appointments_form_type')} value={formData.type} onChange={e => setFormData({...formData, type: e.target.value})}>
            <option value="Consultation">
              {t('patients_modal_action_consultation')} {selectedDoctorForFee ? ` ($${selectedDoctorForFee.consultationFee})` : ''}
            </option>
            <option value="Follow-up">
              {t('patients_modal_action_followUp')} {selectedDoctorForFee ? ` ($${selectedDoctorForFee.consultationFeeFollowup || 0})` : ''}
            </option>
            <option value="Emergency">
              {t('patients_modal_action_emergency')} {selectedDoctorForFee ? ` ($${selectedDoctorForFee.consultationFeeEmergency || 0})` : ''}
            </option>
          </Select>

          <Textarea label={t('appointments_form_reason')} rows={3} value={formData.reason} onChange={e => setFormData({...formData, reason: e.target.value})} />

          <div className="flex justify-end pt-4 gap-3 border-t">
            <Button type="button" variant="secondary" onClick={() => setIsModalOpen(false)}>{t('cancel')}</Button>
            <Button type="submit" disabled={!formData.patientId || !formData.staffId} icon={CheckCircle}>
                {editingAppointment ? t('save') : t('appointments_form_create_button')}
            </Button>
          </div>
        </form>
      </Modal>

      <Modal isOpen={isViewDetailModalOpen} onClose={() => setIsViewDetailModalOpen(false)} title={t('appointments_modal_view_title')}>
        {viewingAppointment && (
          <div className="space-y-6">
            <div className="flex items-center gap-4 p-4 bg-slate-50 dark:bg-slate-900 rounded-2xl border border-slate-100 dark:border-slate-800">
               <div className="w-14 h-14 rounded-full bg-primary-100 dark:bg-primary-900/30 flex items-center justify-center text-primary-600 font-black text-xl">
                  {viewingAppointment.patientName.charAt(0)}
               </div>
               <div className="flex-1">
                  <h3 className="font-black text-lg text-slate-900 dark:text-white leading-tight">{viewingAppointment.patientName}</h3>
                  <p className="text-xs text-slate-500 font-bold uppercase tracking-widest mt-1">ID: {viewingAppointment.dailyToken ? `#${viewingAppointment.dailyToken}` : 'N/A'}</p>
               </div>
               <StatusBadge status={viewingAppointment.status} />
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
               <div className="flex items-center gap-3 p-3 bg-white dark:bg-slate-800 border rounded-xl">
                  <div className="p-2 bg-slate-50 dark:bg-slate-900 rounded-lg text-slate-400"><Stethoscope size={18}/></div>
                  <div>
                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{t('nav_hr')}</p>
                    <p className="text-sm font-bold">{viewingAppointment.staffName}</p>
                  </div>
               </div>
               <div className="flex items-center gap-3 p-3 bg-white dark:bg-slate-800 border rounded-xl">
                  <div className="p-2 bg-slate-50 dark:bg-slate-900 rounded-lg text-slate-400"><Clock size={18}/></div>
                  <div>
                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{t('date')}</p>
                    <p className="text-sm font-bold">{new Date(viewingAppointment.datetime).toLocaleString()}</p>
                  </div>
               </div>
               <div className="flex items-center gap-3 p-3 bg-white dark:bg-slate-800 border rounded-xl">
                  <div className="p-2 bg-slate-50 dark:bg-slate-900 rounded-lg text-slate-400"><Briefcase size={18}/></div>
                  <div>
                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{t('appointments_form_type')}</p>
                    <p className="text-sm font-bold">{viewingAppointment.type}</p>
                  </div>
               </div>
               <div className="flex items-center gap-3 p-3 bg-white dark:bg-slate-800 border rounded-xl">
                  <div className="p-2 bg-slate-50 dark:bg-slate-900 rounded-lg text-slate-400"><Hash size={18}/></div>
                  <div>
                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{t('patients_modal_view_billing_status')}</p>
                    <p className="text-sm font-bold capitalize">{viewingAppointment.billingStatus}</p>
                  </div>
               </div>
            </div>

            <div className="space-y-2">
               <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-1">{t('patients_modal_action_reason')}</h4>
               <div className="p-4 bg-slate-50 dark:bg-slate-900/50 rounded-2xl border italic text-sm text-slate-600 dark:text-slate-300 min-h-[80px]">
                  "{viewingAppointment.reason || 'No specific reason recorded.'}"
               </div>
            </div>

            <div className="pt-4 flex justify-end">
              <Button variant="secondary" onClick={() => setIsViewDetailModalOpen(false)}>{t('close')}</Button>
            </div>
          </div>
        )}
      </Modal>

      <ConfirmationDialog isOpen={confirmState.isOpen} onClose={() => setConfirmState({...confirmState, isOpen: false})} onConfirm={confirmState.action} title={confirmState.title} message={confirmState.message} />
    </div>
  );
};

import React, { ErrorInfo, ReactNode } from 'react';
import { AlertTriangle, RefreshCw } from 'lucide-react';

interface ErrorBoundaryProps {
  children?: ReactNode;
}

interface ErrorBoundaryState {
  hasError: boolean;
  error: Error | null;
}

export class ErrorBoundary extends React.Component<ErrorBoundaryProps, ErrorBoundaryState> {
  public state: ErrorBoundaryState = {
    hasError: false,
    error: null
  };

  static getDerivedStateFromError(error: Error): ErrorBoundaryState {
    return { hasError: true, error };
  }

  componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    console.error('Uncaught error:', error, errorInfo);
  }

  // Soft reload by forcing a state reset.
  // With MemoryRouter, we avoid touching window.location or history API.
  handleReload = () => {
    this.setState({ hasError: false, error: null });
  };

  render() {
    if (this.state.hasError) {
      return (
        <div className="min-h-screen flex items-center justify-center bg-slate-50 dark:bg-slate-900 p-4">
          <div className="bg-white dark:bg-slate-800 p-8 rounded-2xl shadow-xl max-w-md w-full text-center border border-slate-200 dark:border-slate-700">
            <div className="w-16 h-16 bg-red-100 dark:bg-red-900/20 rounded-full flex items-center justify-center mx-auto mb-4 text-red-600 dark:text-red-400">
              <AlertTriangle size={32} />
            </div>
            <h1 className="text-xl font-bold text-slate-900 dark:text-white mb-2">Something went wrong</h1>
            <p className="text-slate-500 dark:text-slate-400 mb-6 text-sm">
              The application encountered an unexpected error.
            </p>

            {this.state.error && (
                <div className="bg-slate-100 dark:bg-slate-950 p-3 rounded-lg text-left text-xs font-mono text-red-600 dark:text-red-400 overflow-auto max-h-32 mb-6">
                    {this.state.error.toString()}
                </div>
            )}

            <button 
              onClick={this.handleReload}
              className="inline-flex items-center justify-center gap-2 px-6 py-3 bg-primary-600 hover:bg-primary-700 text-white font-semibold rounded-xl transition-all w-full"
            >
              <RefreshCw size={18} />
              Try Again
            </button>
          </div>
        </div>
      );
    }

    return this.props.children;
  }
}

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';
import { Card, Button, Badge, Modal, Input, Textarea, Select, ConfirmationDialog } from '../components/UI';
import { 
  Bed, User, Calendar, Activity, CheckCircle, FileText, AlertCircle, AlertTriangle,
  HeartPulse, Clock, LogOut, Plus, Search, Wrench, ArrowRight, 
  DollarSign, Loader2, XCircle, Sparkles, Thermometer, ChevronRight, X, Info, Save, Trash2,
  ExternalLink, ChevronDown, ChevronUp, History, Filter, ChevronLeft, LayoutGrid, Printer, ClipboardList
} from 'lucide-react';
import { api } from '../services/api';
import { useTheme } from '../context/ThemeContext';
import { useTranslation } from '../context/TranslationContext';
import { useAuth } from '../context/AuthContext';
import { useHeader } from '../context/HeaderContext';

export const Admissions = () => {
  const { accent } = useTheme();
  const { t, language } = useTranslation();
  const { user: currentUser } = useAuth();
  const location = useLocation();
  const navigate = useNavigate();

  const [activeMainTab, setActiveMainTab] = useState<'ward' | 'history'>('ward');

  const [beds, setBeds] = useState<any[]>([]);
  const [activeAdmissions, setActiveAdmissions] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [patients, setPatients] = useState<any[]>([]);
  const [staff, setStaff] = useState<any[]>([]);

  // History State
  const [historyAdmissions, setHistoryAdmissions] = useState<any[]>([]);
  const [historyLoading, setHistoryLoading] = useState(false);
  const [historySearch, setHistorySearch] = useState('');
  const [historyFilterStatus, setHistoryFilterStatus] = useState('All');
  const [historyPage, setHistoryPage] = useState(1);
  const [itemsPerPage, setItemsPerPage] = useState(10);

  const [processStatus, setProcessStatus] = useState<'idle' | 'processing' | 'success' | 'error'>('idle');
  const [processMessage, setProcessMessage] = useState('');
  const [confirmState, setConfirmState] = useState<any>({ isOpen: false, title: '', message: '', action: () => {}, type: 'danger' });

  const [isCareModalOpen, setIsCareModalOpen] = useState(false);
  const [isAdmitModalOpen, setIsAdmitModalOpen] = useState(false);
  const [isConfirmModalOpen, setIsConfirmModalOpen] = useState(false);

  const [selectedAdmission, setSelectedAdmission] = useState<any | null>(null);
  const [selectedBedForAdmission, setSelectedBedForAdmission] = useState<any>(null);
  const [inpatientDetails, setInpatientDetails] = useState<any>(null);
  const [careTab, setCareTab] = useState<'overview' | 'notes' | 'reports'>('overview');
  const [expandedBillId, setExpandedBillId] = useState<number | null>(null);

  const [patientSearchTerm, setPatientSearchTerm] = useState('');
  const [showPatientResults, setShowPatientResults] = useState(false);
  const patientSearchRef = useRef<HTMLDivElement>(null);
  const [selectedPatientForAdmission, setSelectedPatientForAdmission] = useState<any>(null);

  const [admitForm, setAdmitForm] = useState({ patientId: '', doctorId: '', entryDate: new Date().toISOString().split('T')[0], deposit: '', notes: '' });
  const [noteForm, setNoteForm] = useState({ note: '', bp: '', temp: '', pulse: '', resp: '' });
  const [dischargeForm, setDischargeForm] = useState({ notes: '', status: 'Recovered' });

  // Sync Header
  useHeader(
    t('admissions_title'), 
    t('admissions_subtitle'),
    <div className="flex bg-slate-100 dark:bg-slate-700 p-1 rounded-lg">
      <button onClick={() => setActiveMainTab('ward')} className={`px-4 py-2 text-sm font-medium rounded-md transition-all flex items-center gap-2 ${activeMainTab === 'ward' ? 'bg-white dark:bg-slate-800 text-primary-600 shadow-sm' : 'text-slate-500 hover:text-slate-700 dark:text-slate-400'}`}>
        <LayoutGrid size={16}/> {t('admissions_title')} <span className="bg-primary-100 text-primary-700 dark:bg-primary-900 text-xs px-2 py-0.5 rounded-full ml-1">{activeAdmissions.length}</span>
      </button>
      <button onClick={() => setActiveMainTab('history')} className={`px-4 py-2 text-sm font-medium rounded-md transition-all flex items-center gap-2 ${activeMainTab === 'history' ? 'bg-white dark:bg-slate-800 text-primary-600 shadow-sm' : 'text-slate-500 hover:text-slate-700 dark:text-slate-400'}`}>
        <History size={16}/> History
      </button>
    </div>
  );

  const loadData = async (silent = false) => {
    if (!silent) setLoading(true);
    try {
      const [bedsData, admissionsData, patientsData, staffData] = await Promise.all([
        api.getBeds(), api.getActiveAdmissions(), api.getPatients(), api.getStaff(),
      ]);
      setBeds(bedsData);
      setActiveAdmissions(admissionsData);
      setPatients(patientsData);
      setStaff(staffData);

      const state = location.state as any;
      if (state?.trigger === 'new') {
        const availableBed = bedsData.find((b: any) => b.status === 'available');
        if (availableBed) handleBedClick(availableBed);
        else setProcessStatus('error'), setProcessMessage('No beds available for new admission.');
      }
    } catch (e) { console.error(e); } finally { if (!silent) setLoading(false); }
  };

  const loadHistory = async () => {
    setHistoryLoading(true);
    try {
        const data = await api.getAdmissionsHistory();
        setHistoryAdmissions(data);
    } catch(e) { console.error(e); }
    finally { setHistoryLoading(false); }
  };

  useEffect(() => { loadData(); }, []);
  useEffect(() => { if (activeMainTab === 'history') loadHistory(); }, [activeMainTab]);

  useEffect(() => {
    const handleClickOutside = (e: MouseEvent) => {
      if (patientSearchRef.current && !patientSearchRef.current.contains(e.target as Node)) {
        setShowPatientResults(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const calculateDays = (dateString: string, endDateString?: string) => {
    if (!dateString) return 0;
    const start = new Date(dateString);
    const end = endDateString ? new Date(endDateString) : new Date();
    const diff = Math.abs(end.getTime() - start.getTime());
    return Math.ceil(diff / (1000 * 60 * 60 * 24)) || 1;
  };

  const handleBedClick = async (bed: any) => {
    if (bed.status === 'reserved') {
      const admission = activeAdmissions.find(a => a.bedId === bed.id && a.status === 'reserved');
      if (admission) { 
        setSelectedAdmission(admission); 
        setIsConfirmModalOpen(true); 
      }
      return;
    }

    if (bed.status === 'occupied') {
      const admission = activeAdmissions.find(a => a.bedId === bed.id && a.status === 'active');
      if (admission) {
        handleViewAdmissionDetails(admission.id);
      }
      return;
    }

    if (bed.status === 'available') {
      setSelectedBedForAdmission(bed);
      setAdmitForm({ 
        patientId: '', 
        doctorId: '', 
        entryDate: new Date().toISOString().split('T')[0], 
        deposit: bed.costPerDay.toString(), 
        notes: '' 
      });
      setPatientSearchTerm('');
      setSelectedPatientForAdmission(null);
      setIsAdmitModalOpen(true);
      return;
    }

    if (bed.status === 'cleaning') {
      setConfirmState({ 
        isOpen: true, 
        title: 'Mark as Cleaned', 
        message: 'Is the room sanitized and ready for the next patient?', 
        type: 'info', 
        action: async () => { 
          await api.markBedClean(bed.id); 
          loadData(true); 
        } 
      });
    }
  };

  const handleViewAdmissionDetails = async (admissionId: number) => {
    setProcessStatus('processing');
    setProcessMessage('Loading inpatient chart...');
    try {
      const details = await api.getInpatientDetails(admissionId);
      setInpatientDetails(details);
      // Pre-fill discharge form if data exists
      if (details.status === 'discharged') {
          setDischargeForm({
              status: details.discharge_status || 'Recovered',
              notes: details.discharge_notes || ''
          });
      } else {
          setDischargeForm({ status: 'Recovered', notes: '' });
      }
      setCareTab('overview');
      setExpandedBillId(null);
      setIsCareModalOpen(true);
    } catch (e) {
      console.error(e);
    } finally {
      setProcessStatus('idle');
    }
  };

  const handleAdmitSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedBedForAdmission || !selectedPatientForAdmission || !admitForm.doctorId) return;

    setProcessStatus('processing');
    setProcessMessage('Creating admission record...');
    try {
      await api.createAdmission({ 
        patientId: selectedPatientForAdmission.id, 
        bedId: selectedBedForAdmission.id, 
        doctorId: parseInt(admitForm.doctorId), 
        entryDate: admitForm.entryDate, 
        deposit: parseFloat(admitForm.deposit), 
        notes: admitForm.notes 
      });
      setProcessStatus('success');
      await loadData(true);
      setTimeout(() => { setIsAdmitModalOpen(false); setProcessStatus('idle'); }, 1500);
    } catch (err: any) { 
      setProcessStatus('error'); 
      setProcessMessage(err.response?.data?.error || 'Failed to admit patient.'); 
    }
  };

  const handleConfirmAdmission = async () => {
    if (!selectedAdmission) return;
    setProcessStatus('processing');
    setProcessMessage('Confirming patient arrival and occupancy...');
    try {
      await api.confirmAdmissionDeposit(selectedAdmission.id);
      setProcessStatus('success');
      await loadData(true);
      setTimeout(() => { setIsConfirmModalOpen(false); setProcessStatus('idle'); }, 1500);
    } catch (err: any) { 
      setProcessStatus('error'); 
      setProcessMessage(err.response?.data?.error || 'Failed to confirm arrival. Ensure deposit is paid.'); 
    }
  };

  const handleCancelAdmission = () => {
    if (!selectedAdmission) return;
    setConfirmState({
      isOpen: true,
      title: t('admissions_bed_cancel_reservation'),
      message: 'Are you sure you want to cancel this reservation? This will free up the bed.',
      type: 'danger',
      action: async () => {
        setProcessStatus('processing');
        setProcessMessage('Cancelling reservation...');
        try {
          await api.cancelAdmission(selectedAdmission.id);
          setProcessStatus('success');
          await loadData(true);
          setTimeout(() => { setIsConfirmModalOpen(false); setProcessStatus('idle'); }, 1500);
        } catch (e) {
          setProcessStatus('error');
          setProcessMessage('Failed to cancel reservation.');
        }
      }
    });
  };

  const handleAddNote = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!inpatientDetails || !noteForm.note) return;
    setProcessStatus('processing');
    setProcessMessage('Saving clinical note...');
    try {
      await api.addInpatientNote(inpatientDetails.id, {
        doctorId: inpatientDetails.doctorId,
        note: noteForm.note,
        vitals: {
          bp: noteForm.bp,
          temp: noteForm.temp,
          pulse: noteForm.pulse,
          resp: noteForm.resp
        }
      });
      const updated = await api.getInpatientDetails(inpatientDetails.id);
      setInpatientDetails(updated);
      setNoteForm({ note: '', bp: '', temp: '', pulse: '', resp: '' });
      setProcessStatus('success');
      setTimeout(() => setProcessStatus('idle'), 1000);
    } catch (e) {
      setProcessStatus('error');
      setProcessMessage('Failed to save note.');
    }
  };

  const handleDischarge = () => {
    if (!inpatientDetails) return;
    const totalDue = inpatientDetails.unpaidBills?.reduce((sum: number, b: any) => sum + (b.total_amount - (b.paid_amount || 0)), 0) || 0;
    if (totalDue > 0.01) {
      setProcessStatus('error');
      setProcessMessage(`Patient discharge blocked. There is an outstanding balance of $${totalDue.toLocaleString()}. Please settle all invoices in the Billing section before proceeding.`);
      return;
    }
    setConfirmState({
      isOpen: true, 
      title: t('admissions_dialog_discharge_title'), 
      message: t('admissions_dialog_discharge_message'),
      action: async () => {
        setProcessStatus('processing');
        setProcessMessage('Processing final discharge logic...');
        try {
          await api.dischargePatient(inpatientDetails.id, { 
            dischargeNotes: dischargeForm.notes, 
            dischargeStatus: dischargeForm.status 
          });
          setProcessStatus('success');
          await loadData(true);
          // Refresh details to show read-only state
          const updated = await api.getInpatientDetails(inpatientDetails.id);
          setInpatientDetails(updated);
          setTimeout(() => { setProcessStatus('idle'); }, 1000);
        } catch (e: any) { 
          setProcessStatus('error'); 
          setProcessMessage(e.response?.data?.error || 'Ensure all bills are paid before discharge.'); 
        }
      }
    });
  };

  const filteredPatientsForAdmission = patients.filter(p => {
    const matchesSearch = p.fullName.toLowerCase().includes(patientSearchTerm.toLowerCase()) || (p.patientId && p.patientId.toLowerCase().includes(patientSearchTerm.toLowerCase()));
    const isAlreadyAdmitted = activeAdmissions.some(a => a.patientId === p.id);
    return matchesSearch && !isAlreadyAdmitted && p.type !== 'inpatient';
  }).slice(0, 5);

  const totalOutstandingBalance = useMemo(() => {
    if (!inpatientDetails?.unpaidBills) return 0;
    return inpatientDetails.unpaidBills.reduce((sum: number, b: any) => sum + (b.total_amount - (b.paid_amount || 0)), 0);
  }, [inpatientDetails]);

  // History Filtering Logic
  const filteredHistory = useMemo(() => {
    return historyAdmissions.filter(a => {
        const matchesSearch = a.patientName.toLowerCase().includes(historySearch.toLowerCase()) || (a.patientCode && a.patientCode.toLowerCase().includes(historySearch.toLowerCase()));
        const matchesStatus = historyFilterStatus === 'All' || a.status === historyFilterStatus.toLowerCase();
        return matchesSearch && matchesStatus;
    });
  }, [historyAdmissions, historySearch, historyFilterStatus]);

  const paginatedHistory = filteredHistory.slice((historyPage - 1) * itemsPerPage, historyPage * itemsPerPage);
  const totalHistoryPages = Math.ceil(filteredHistory.length / itemsPerPage);

  const getStatusBadge = (status: string) => {
      switch(status) {
          case 'active': return <Badge color="red">Occupied</Badge>;
          case 'reserved': return <Badge color="blue">Reserved</Badge>;
          case 'discharged': return <Badge color="green">Discharged</Badge>;
          case 'cancelled': return <Badge color="gray">Cancelled</Badge>;
          default: return <Badge color="gray">{status}</Badge>;
      }
  };

  return (
    <div className="space-y-6">
      {processStatus !== 'idle' && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center bg-black/60 backdrop-blur-sm animate-in fade-in">
          <div className="bg-white dark:bg-slate-900 p-8 rounded-3xl shadow-2xl flex flex-col items-center max-w-sm w-full mx-4 text-center">
            {processStatus === 'processing' && <><Loader2 className="w-12 h-12 text-primary-600 animate-spin mb-4" /><h3 className="font-bold text-slate-900 dark:text-white">{t('processing')}</h3></>}
            {processStatus === 'success' && <><CheckCircle size={48} className="text-green-600 mb-4" /><h3 className="font-bold text-slate-900 dark:text-white">{t('success')}</h3></>}
            {processStatus === 'error' && <><XCircle size={48} className="text-red-600 mb-4" /><h3 className="font-bold text-slate-900 dark:text-white">{t('patients_process_title_failed')}</h3><p className="text-sm text-red-500 mt-2 leading-relaxed">{processMessage}</p><Button variant="secondary" className="mt-4 w-full" onClick={() => setProcessStatus('idle')}>{t('close')}</Button></>}
          </div>
        </div>
      )}

      {activeMainTab === 'ward' && (
        <>
            <div className="flex gap-3 text-xs font-black uppercase tracking-widest flex-wrap mb-2 no-print">
                <div className="flex items-center gap-2 px-3 py-1.5 bg-green-50 dark:bg-green-900/20 text-green-700 dark:text-green-400 rounded-lg border border-green-100 dark:border-green-800"><div className="w-2 h-2 rounded-full bg-green-500"></div> {t('admissions_legend_available')}</div>
                <div className="flex items-center gap-2 px-3 py-1.5 bg-blue-50 dark:bg-blue-900/40 text-blue-700 dark:text-blue-400 rounded-lg border border-blue-200 dark:border-blue-800"><div className="w-2 h-2 rounded-full bg-blue-500 shadow-[0_0_8px_rgba(59,130,246,0.5)]"></div> {t('admissions_legend_reserved')}</div>
                <div className="flex items-center gap-2 px-3 py-1.5 bg-red-50 dark:bg-red-900/40 text-red-700 dark:text-red-400 rounded-lg border border-red-200 dark:border-red-800"><div className="w-2 h-2 rounded-full bg-red-500 shadow-[0_0_8px_rgba(239,68,68,0.5)]"></div> {t('admissions_legend_occupied')}</div>
                <div className="flex items-center gap-2 px-3 py-1.5 bg-purple-50 dark:bg-purple-900/20 text-purple-700 dark:text-purple-400 rounded-lg border border-purple-100 dark:border-purple-800"><div className="w-2 h-2 rounded-full bg-purple-500"></div> Cleaning</div>
            </div>

            <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-5 gap-4">
                {loading ? <div className="col-span-full py-20 text-center"><Loader2 className="animate-spin mx-auto text-primary-600 mb-2"/><p className="text-slate-500 font-medium">{t('admissions_loading')}</p></div> : 
                beds.map(bed => {
                const admission = activeAdmissions.find(a => a.bedId === bed.id);
                const isOccupied = bed.status === 'occupied';
                const isReserved = bed.status === 'reserved';
                return (
                    <div 
                    key={bed.id} 
                    onClick={() => handleBedClick(bed)} 
                    className={`relative p-5 rounded-2xl border-2 transition-all cursor-pointer group flex flex-col h-52 shadow-sm hover:shadow-xl hover:-translate-y-1 ${
                        isOccupied ? 'bg-red-50/30 dark:bg-red-900/10 border-red-200 dark:border-red-900/50 hover:border-red-400' : 
                        isReserved ? 'bg-blue-50 dark:bg-blue-900/20 border-blue-300 dark:border-blue-800 hover:border-blue-500' : 
                        bed.status === 'cleaning' ? 'bg-purple-50 dark:bg-purple-900/20 border-purple-200 hover:border-purple-400' : 
                        'bg-green-50/50 dark:bg-green-900/10 border-green-200 hover:border-green-400'
                    }`}
                    >
                    <div className="flex justify-between items-start mb-3">
                        <div>
                        <h3 className="font-black text-slate-800 dark:text-white text-xl leading-none">{bed.roomNumber}</h3>
                        <p className="text-[10px] font-black uppercase text-slate-400 mt-1 tracking-widest">{bed.type}</p>
                        </div>
                        <div className={`w-3 h-3 rounded-full shrink-0 shadow-sm ${isOccupied ? 'bg-red-500 animate-pulse' : isReserved ? 'bg-blue-500' : bed.status === 'cleaning' ? 'bg-purple-500' : 'bg-green-500'}`} />
                    </div>
                    <div className="flex-1 flex flex-col justify-center items-center w-full">
                        {isOccupied || isReserved ? (
                        <div className="w-full text-center">
                            <p className="text-sm font-black text-slate-900 dark:text-white line-clamp-2 leading-tight mb-2 min-h-[2.5rem]">{admission?.patientName}</p>
                            <div className="flex justify-between items-center text-[10px] font-bold text-slate-500 dark:text-slate-400 w-full border-t border-slate-200 dark:border-slate-700 pt-2">
                            <span className="truncate max-w-[60%]">Dr. {admission?.doctorName}</span>
                            <span className="bg-white dark:bg-slate-800 px-1.5 py-0.5 rounded border">{calculateDays(admission?.entry_date)}d</span>
                            </div>
                        </div>
                        ) : (
                        <div className="text-center opacity-40 group-hover:opacity-100 transition-all duration-300 transform group-hover:scale-110">
                            <Plus size={40} className="text-slate-300 dark:text-slate-600 mx-auto mb-1"/>
                            <p className="text-[10px] font-black uppercase tracking-widest text-slate-400">{bed.status === 'cleaning' ? 'Cleaning' : 'Available'}</p>
                        </div>
                        )}
                    </div>
                    </div>
                )
                })}
            </div>
        </>
      )}

      {activeMainTab === 'history' && (
        <Card className="!p-0 border border-slate-200 dark:border-slate-700 shadow-sm overflow-hidden animate-in fade-in">
            <div className="p-4 bg-slate-50 dark:bg-slate-900/50 border-b border-slate-200 dark:border-slate-700 flex flex-col md:flex-row gap-4 justify-between">
                <div className="relative w-full md:w-96">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-4 h-4" />
                    <input 
                        type="text" 
                        placeholder={t('patients_search_placeholder')}
                        className="pl-9 pr-4 py-2 w-full rounded-lg border border-slate-300 dark:border-slate-600 bg-white dark:bg-slate-800 text-sm focus:ring-2 focus:ring-primary-500 outline-none"
                        value={historySearch}
                        onChange={e => { setHistorySearch(e.target.value); setHistoryPage(1); }}
                    />
                </div>
                <div className="flex gap-2 items-center">
                    <Filter className="text-slate-400 w-4 h-4" />
                    <select 
                        className="pl-2 pr-8 py-2 rounded-lg border border-slate-300 dark:border-slate-600 bg-white dark:bg-slate-800 text-sm focus:ring-2 focus:ring-primary-500 outline-none cursor-pointer"
                        value={historyFilterStatus}
                        onChange={e => { setHistoryFilterStatus(e.target.value); setHistoryPage(1); }}
                    >
                        <option value="All">All Statuses</option>
                        <option value="active">Active (Occupied)</option>
                        <option value="discharged">Discharged</option>
                        <option value="cancelled">Cancelled</option>
                        <option value="reserved">Reserved</option>
                    </select>
                </div>
            </div>

            <div className="overflow-x-auto min-h-[400px]">
                <table className="min-w-full divide-y divide-slate-200 dark:divide-slate-700">
                    <thead className="bg-slate-50 dark:bg-slate-900/50">
                        <tr>
                            <th className="px-6 py-3 text-left text-xs font-bold text-slate-500 uppercase tracking-wider">{t('patients_table_header_patient')}</th>
